function mapLimit(inputs, limit, iterateeFn, callback) {
  const results = new Array(inputs.length);
  let nextIndex = 0;
  let totalOperationsDone = 0;

  function executeFn(currentIndex) {
    iterateeFn(inputs[currentIndex], (data) => {
      results[currentIndex] = data;

      totalOperationsDone++;

      if (totalOperationsDone === inputs.length) {
        callback(results);
      } else if (nextIndex + 1 < inputs.length) {
        executeFn(nextIndex + 1);
        nextIndex++;
      }
    });
  }

  /**
   * This maxWindowSize make sure that if limit is larger than the input length
   */
  const maxWindowSize = Math.min(limit, inputs.length);
  for (let i = 0; i < maxWindowSize; i++) {
    nextIndex = i;
    executeFn(i);
  }
}
//example:
mapLimit([1, 2, 3, 4, 5], 2, getNameById, (allResults) => {
  console.log("output", allResults); // ["User1", "User2", "User3", "User4", "User5"]
});

