async function mapLimit(inputs, limit, iterateeFn, callback) {
  // break inputs into chunks of size=limit
  const chunks = []
  for(let i=0; i<inputs.length; i+=limit){
    chunks.push(inputs.slice(i, i+limit))
  }

  const output = [];
  for(let chunk of chunks){
    const promises = chunk.map(id => new Promise(res => iterateeFn(id, res)))
    const results = await Promise.all(promises) // awaiting here bcz we want max 2 (LIMIT) inputs to be processed at a time;
    output.push(...results)
  }

  callback(output)
}
