function mapLimit(inputs, limit, iterateeFn, cb) {
  const result = []
  let  count = 0;
  let currentItemIndex = 0
  const iterateeCb = (index,res) => {
    if(currentItemIndex < inputs.length){
      let id = currentItemIndex
      iterateeFn(inputs[currentItemIndex], (res) => iterateeCb(id, res))
    }
    currentItemIndex++;
    count++
    result[index] = res;
    if(count === inputs.length-1){
      cb(result)
    }

  }
  for (let i = 0; i < limit; i++) {
    const input = inputs[i];
    iterateeFn(input, (res) => iterateeCb(i, res))
    currentItemIndex++
  }
}
